import './health-meals-screen.css';
import { buildSectionPage } from '../../../utils/section-page.utils.js';
import {
    HEALTH_EVENTS,
    type AddIngredientEvent,
    type PickerCancelEvent,
    type ScanBarcodeEvent,
    type AiEstimateEvent,
    type MealCardOpenPickerEvent,
    type MealCardSaveEvent,
    type MealCardDeleteEvent,
    type MealCardCancelEvent,
} from '../health-events.js';
import {
    type FoodItem,
    type MealWithIngredients,
    type NewMealWithIngredients,
    uuidv7,
} from '@motivation/shared';
import { goBack, navigate } from '../../../router.js';
import { saveDraft, readDraft, clearDraft, type StoredMealDraft } from './meal-draft-storage.js';
import { HealthService } from '../../../services/health.service.js';
import type { ScreenComponent } from '../../../types/screen-component.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../../_shared/screen-status.js';
import { safeExec } from '../../../utils/safe-exec.js';
import './meal-card/meal-card.component.js';
import type { MealCard } from './meal-card/meal-card.component.js';
import '../meal-ingredient-picker/meal-ingredient-picker.component.js';
import type { MealIngredientPicker } from '../meal-ingredient-picker/meal-ingredient-picker.component.js';

interface PickerSession {
    card: MealCard;
    editingIndex: number | null;
}

interface FromSelectionState {
    /** Selected source entry IDs in display order, after filtering for live food items. */
    linkEntryIds: string[];
    /** The card that owns the prefilled draft — used to detect the save target. */
    card: MealCard;
    /** Entry IDs that were dropped because their food_item no longer exists. */
    skippedEntryIds: string[];
}

export class HealthMealsScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private pickerSession: PickerSession | null = null;
    private focusValue: string | null = null;
    private fromSelectionIds: string[] | null = null;
    private fromSelectionState: FromSelectionState | null = null;
    private addIngredientBarcode: string | null = null;
    private addIngredientFoodId: string | null = null;

    private listView!: HTMLElement;
    private listEl!: HTMLElement;
    private pickerHost!: HTMLElement;
    private picker: MealIngredientPicker | null = null;

    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);
    private readonly log = createComponentLogger('health-meals-screen');

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    set query(value: URLSearchParams | null) {
        this.focusValue = value?.get('focus') ?? null;
        const raw = value?.get('fromSelection') ?? null;
        this.fromSelectionIds = raw
            ? raw.split(',').map((s) => s.trim()).filter(Boolean)
            : null;
        this.addIngredientBarcode = value?.get('addIngredientBarcode') ?? null;
        this.addIngredientFoodId = value?.get('addIngredientFoodId') ?? null;
        if (this.initialized) this.applyFocus();
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Health · Meals', 'health', '/health');

        this.statusNodes.loadingNode.textContent = 'Loading meals…';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.refresh(); });

        this.listView = document.createElement('div');
        this.listView.className = 'meals-container';
        const toolbar = document.createElement('div');
        toolbar.className = 'toolbar';
        const newBtn = document.createElement('button');
        newBtn.type = 'button';
        newBtn.className = 'btn-primary';
        newBtn.textContent = '+ New meal';
        newBtn.addEventListener('click', () => this.startNewMeal());
        toolbar.appendChild(newBtn);
        this.listEl = document.createElement('div');
        this.listEl.className = 'meals-list';
        this.listView.append(toolbar, this.listEl);

        this.pickerHost = document.createElement('div');
        this.pickerHost.hidden = true;

        page.content.append(
            this.statusNodes.loadingNode,
            this.statusNodes.errorNode,
            this.statusNodes.retryNode,
            this.listView,
            this.pickerHost,
        );

        // Card intents.
        this.addEventListener(HEALTH_EVENTS.MEAL_CARD_OPEN_PICKER, (event: MealCardOpenPickerEvent) => {
            event.stopPropagation();
            const card = event.target as MealCard;
            this.openPicker(card, event.detail.editingIndex);
        });
        this.addEventListener(HEALTH_EVENTS.MEAL_CARD_SAVE, (event: MealCardSaveEvent) => {
            event.stopPropagation();
            void this.handleSave(event.target as MealCard);
        });
        this.addEventListener(HEALTH_EVENTS.MEAL_CARD_DELETE, (event: MealCardDeleteEvent) => {
            event.stopPropagation();
            void this.handleDelete(event.target as MealCard);
        });
        this.addEventListener(HEALTH_EVENTS.MEAL_CARD_CANCEL, (event: MealCardCancelEvent) => {
            event.stopPropagation();
            const card = event.target as MealCard;
            if (this.fromSelectionState?.card === card) {
                this.fromSelectionState = null;
                this.fromSelectionIds = null;
                this.listView.querySelector('.from-selection-banner')?.remove();
            }
            clearDraft();
            card.remove();
        });

        // Picker outcomes.
        this.addEventListener(HEALTH_EVENTS.ADD_INGREDIENT, (event: AddIngredientEvent) => {
            event.stopPropagation();
            this.commitPickerResult(event.detail.food_item, event.detail.amount);
        });
        this.addEventListener(HEALTH_EVENTS.PICKER_CANCEL, (event: PickerCancelEvent) => {
            event.stopPropagation();
            this.closePicker();
        });

        // Scan / AI side-trip: serialize the active draft and navigate.
        this.addEventListener(HEALTH_EVENTS.SCAN_BARCODE, (event: ScanBarcodeEvent) => {
            event.stopPropagation();
            this.launchSideTrip('/health/scanner');
        });
        this.addEventListener(HEALTH_EVENTS.AI_ESTIMATE, (event: AiEstimateEvent) => {
            event.stopPropagation();
            this.launchSideTrip('/health/ai-estimate');
        });

        void this.refresh();
    }

    private async refresh(): Promise<void> {
        return safeExec(this, this.log, async () => {
            const summaries = await HealthService.listMeals();
            const detailed = await Promise.all(summaries.map((m) => HealthService.fetchMeal(m.id)));
            this.log.debug('refresh', { count: detailed.length, focus: this.focusValue });
            this.renderList(detailed);
            if (this.fromSelectionIds && this.fromSelectionIds.length > 0 && !this.fromSelectionState) {
                await this.startFromSelectionDraft(this.fromSelectionIds);
            }
            await this.maybeRehydrateDraft();
        });
    }

    /**
     * Restore a sessionStorage draft and, if the URL carries an `addIngredient*`
     * param, open the picker on the restored card with the chosen ingredient.
     * If we returned to this screen by some other path, clear the slot.
     */
    private async maybeRehydrateDraft(): Promise<void> {
        const returningFromSideTrip = this.addIngredientBarcode !== null || this.addIngredientFoodId !== null;
        const stored = readDraft();
        if (!stored) {
            return;
        }
        if (!returningFromSideTrip) {
            this.log.debug('clean mount — discarding stale stored draft');
            clearDraft();
            return;
        }

        const card = await this.mountRestoredDraft(stored);
        this.openPicker(card, null);
        if (this.addIngredientBarcode) {
            await this.picker!.lookupBarcode(this.addIngredientBarcode);
        } else if (this.addIngredientFoodId) {
            const item = await HealthService.fetchFoodItem(this.addIngredientFoodId);
            if (item) this.picker!.showLibraryItem(item);
        }
    }

    private async mountRestoredDraft(stored: StoredMealDraft): Promise<MealCard> {
        const foods = await Promise.all(stored.ingredients.map((i) => HealthService.fetchFoodItem(i.food_item_id)));
        const ingredients: { food_item: FoodItem; amount: number }[] = [];
        for (let i = 0; i < stored.ingredients.length; i++) {
            const food = foods[i];
            if (food) ingredients.push({ food_item: food, amount: stored.ingredients[i].amount });
        }

        const card = document.createElement('meal-card') as MealCard;
        card.initialDraft = {
            id: stored.id,
            name: stored.name,
            notes: stored.notes,
            default_scale: stored.default_scale,
            image_path: stored.image_path,
            ingredients,
        };

        if (stored.id) {
            const existing = this.listEl.querySelector(`meal-card[data-draft-id="${CSS.escape(stored.id)}"]`);
            if (existing) {
                existing.replaceWith(card);
                return card;
            }
        }
        this.listEl.prepend(card);
        return card;
    }

    private serializeDraft(card: MealCard): StoredMealDraft {
        const draft = card.getDraft();
        return {
            id: draft.id,
            name: draft.name,
            notes: draft.notes,
            default_scale: draft.default_scale,
            image_path: draft.image_path,
            ingredients: draft.ingredients.map((i) => ({ food_item_id: i.food_item.id, amount: i.amount })),
        };
    }

    private launchSideTrip(target: '/health/scanner' | '/health/ai-estimate'): void {
        const card = this.pickerSession?.card;
        if (!card) {
            this.log.warn('side-trip dispatched without an active picker session — ignoring');
            return;
        }
        saveDraft(this.serializeDraft(card));
        navigate(`${target}?return=${encodeURIComponent('/health/meals')}`, { history: 'replace' });
    }

    private async startFromSelectionDraft(entryIds: string[]): Promise<void> {
        const entries = await Promise.all(entryIds.map((id) => HealthService.fetchConsumptionEntry(id)));
        // Resolve each entry's food_item. Entries whose food_item_id no longer
        // resolves (or whose own row disappeared) are dropped from the draft
        // and surfaced as a warning so the user can still save the rest.
        const liveEntries: { id: string; food_item_id: string; amount: number }[] = [];
        const skipped: string[] = [];
        for (let i = 0; i < entries.length; i++) {
            const entry = entries[i];
            const requestedId = entryIds[i];
            if (!entry) { skipped.push(requestedId); continue; }
            liveEntries.push({ id: entry.id, food_item_id: entry.food_item_id, amount: entry.amount });
        }

        const uniqueFoodIds = [...new Set(liveEntries.map((e) => e.food_item_id))];
        const foodItems = await Promise.all(uniqueFoodIds.map((id) => HealthService.fetchFoodItem(id)));
        const foodById = new Map(foodItems.filter((f) => f !== null).map((f) => [f!.id, f!] as const));

        const ingredients: { food_item: FoodItem; amount: number }[] = [];
        const linkableEntryIds: string[] = [];
        for (const e of liveEntries) {
            const food = foodById.get(e.food_item_id);
            if (!food) { skipped.push(e.id); continue; }
            ingredients.push({ food_item: food, amount: e.amount });
            linkableEntryIds.push(e.id);
        }

        if (ingredients.length === 0) {
            this.log.warn('fromSelection produced no ingredients', { entryIds, skipped });
            this.renderFromSelectionWarning(skipped, 0);
            return;
        }

        const card = document.createElement('meal-card') as MealCard;
        card.initialDraft = { name: '', notes: '', default_scale: 1, ingredients };
        this.listEl.prepend(card);
        this.fromSelectionState = { linkEntryIds: linkableEntryIds, card, skippedEntryIds: skipped };
        this.renderFromSelectionWarning(skipped, ingredients.length);

        // Auto-focus the name input so the user starts typing immediately.
        // The card's open <details> + the focus call together fulfill the
        // "open expanded, name input focused" acceptance criterion.
        requestAnimationFrame(() => {
            const nameInput = card.shadowRoot?.querySelector<HTMLInputElement>('[data-field="name"]');
            nameInput?.focus();
        });
    }

    private renderFromSelectionWarning(skippedIds: string[], _ingredientCount: number): void {
        let banner = this.listView.querySelector<HTMLElement>('.from-selection-banner');
        if (!banner) {
            banner = document.createElement('div');
            banner.className = 'from-selection-banner';
            this.listView.insertBefore(banner, this.listEl);
        }
        if (skippedIds.length === 0) {
            banner.textContent = 'Pre-filled from your selection. Add a name and save to create the meal template.';
            banner.classList.remove('warn');
            return;
        }
        banner.classList.add('warn');
        banner.textContent = `Skipped ${skippedIds.length} entr${skippedIds.length === 1 ? 'y' : 'ies'} whose food item is missing. You can still save the rest.`;
    }

    private renderList(meals: MealWithIngredients[]): void {
        this.listEl.replaceChildren();
        if (meals.length === 0) {
            const empty = document.createElement('div');
            empty.className = 'empty-state';
            empty.textContent = 'No meals yet. Tap "+ New meal" to create one.';
            this.listEl.appendChild(empty);
            return;
        }
        for (const meal of meals) {
            this.listEl.appendChild(this.createCardFromMeal(meal));
        }
        this.applyFocus();
    }

    private createCardFromMeal(meal: MealWithIngredients): MealCard {
        const card = document.createElement('meal-card') as MealCard;
        card.initialDraft = {
            id: meal.id,
            name: meal.name,
            notes: meal.notes ?? '',
            default_scale: meal.default_scale,
            image_path: meal.image_path,
            ingredients: meal.ingredients.map((i) => ({ food_item: i.food_item, amount: i.amount })),
        };
        return card;
    }

    private applyFocus(): void {
        if (!this.focusValue) return;
        const card = this.listEl.querySelector(`meal-card[data-draft-id="${CSS.escape(this.focusValue)}"]`) as MealCard | null;
        if (card) {
            card.expand();
            card.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
    }

    private startNewMeal(): void {
        // Only one in-flight new draft at a time — if an unsaved card exists,
        // focus it instead of stacking a second.
        const existing = Array.from(this.listEl.querySelectorAll<MealCard>('meal-card'))
            .find((c) => !c.dataset.draftId);
        if (existing) {
            existing.expand();
            existing.scrollIntoView({ behavior: 'smooth', block: 'start' });
            return;
        }
        const card = document.createElement('meal-card') as MealCard;
        card.initialDraft = { name: '', notes: '', default_scale: 1, ingredients: [] };
        this.listEl.prepend(card);
    }

    private openPicker(card: MealCard, editingIndex: number | null): void {
        this.log.debug('openPicker', { draftId: card.dataset.draftId ?? '(new)', editingIndex });
        this.pickerSession = { card, editingIndex };
        this.pickerHost.replaceChildren();
        this.picker = document.createElement('meal-ingredient-picker') as MealIngredientPicker;
        this.picker.title = editingIndex === null ? 'Add ingredient' : 'Edit ingredient';
        if (editingIndex !== null) {
            const ing = card.getDraft().ingredients[editingIndex];
            if (ing) this.picker.showLibraryItem(ing.food_item, ing.amount);
        }
        this.pickerHost.appendChild(this.picker);
        this.listView.hidden = true;
        this.pickerHost.hidden = false;
    }

    private closePicker(): void {
        this.pickerSession = null;
        this.pickerHost.replaceChildren();
        this.picker = null;
        this.pickerHost.hidden = true;
        this.listView.hidden = false;
    }

    private commitPickerResult(food: NonNullable<ReturnType<MealCard['getDraft']>['ingredients'][number]>['food_item'], amount: number): void {
        const session = this.pickerSession;
        if (!session) {
            this.log.warn('picker commit with no session — dropping result', { foodItemId: food.id });
            this.closePicker();
            return;
        }
        this.log.debug('picker commit', { foodItemId: food.id, amount, editingIndex: session.editingIndex });
        session.card.setIngredient(session.editingIndex, food, amount);
        this.closePicker();
    }

    private async handleSave(card: MealCard): Promise<void> {
        const draft = card.getDraft();
        const payload: NewMealWithIngredients = {
            name: draft.name.trim(),
            notes: draft.notes.trim() || undefined,
            default_scale: draft.default_scale,
            image_path: draft.image_path,
            ingredients: draft.ingredients.map((i) => ({ food_item_id: i.food_item.id, amount: i.amount })),
        };
        const linkSession = this.fromSelectionState?.card === card ? this.fromSelectionState : null;
        this.log.debug('save', {
            id: draft.id ?? '(new)',
            name: payload.name,
            ingredients: payload.ingredients.length,
            default_scale: payload.default_scale,
            link_entry_count: linkSession?.linkEntryIds.length ?? 0,
        });
        return safeExec(this, this.log, async () => {
            clearDraft();
            if (draft.id) {
                await HealthService.updateMeal(draft.id, payload);
            } else if (linkSession) {
                const created = await HealthService.createMeal(payload);
                const occurrenceId = uuidv7();
                // Parallel PATCHes — fail-loud on any rejection. For a single-user
                // app the rare partial-link case is acceptable; the user can re-do
                // the linkage manually if it ever happens.
                await Promise.all(linkSession.linkEntryIds.map((entryId) =>
                    HealthService.updateConsumptionEntry(entryId, {
                        source_meal_id: created.id,
                        meal_occurrence_id: occurrenceId,
                    }),
                ));
                this.fromSelectionState = null;
                this.fromSelectionIds = null;
                goBack('/health');
                return;
            } else {
                await HealthService.createMeal(payload);
            }
            const summaries = await HealthService.listMeals();
            const detailed = await Promise.all(summaries.map((m) => HealthService.fetchMeal(m.id)));
            this.renderList(detailed);
        });
    }

    private async handleDelete(card: MealCard): Promise<void> {
        const draft = card.getDraft();
        if (!draft.id) return;
        this.log.debug('delete', { id: draft.id, name: draft.name });
        return safeExec(this, this.log, async () => {
            await HealthService.deleteMeal(draft.id!);
            const summaries = await HealthService.listMeals();
            const detailed = await Promise.all(summaries.map((m) => HealthService.fetchMeal(m.id)));
            this.renderList(detailed);
        });
    }
}

if (!customElements.get('health-meals-screen')) {
    customElements.define('health-meals-screen', HealthMealsScreen);
}
